// The two `forall|i|` ensures (one for post1, one for post2) have disjoint
// triggers (`post1_self_.page_array@[i]` vs. `post2_self_.page_array@[i]`),
// so z3 never aligns them. Close the gap by case-splitting on `i == index`
// inside an `assert forall ... by` whose body mentions both triggers, then
// lift the resulting pointwise Page equality to a Seq extensional equality.
assert forall|i: int| 0 <= i < NUM_PAGES implies
    post1_self_.page_array@[i] == post2_self_.page_array@[i] by {
    if i == index as int {
        // At i == index, every field of post1/post2's Page is pinned by an
        // index-specific ensures: 7 fields to pre_self_'s corresponding field,
        // and `mappings` to the input ghost set `mapping`. So both Pages
        // agree field-by-field, hence the structs are equal.
        assert(post1_self_.page_array@[i].addr == pre_self_.page_array@[i].addr);
        assert(post2_self_.page_array@[i].addr == pre_self_.page_array@[i].addr);
        assert(post1_self_.page_array@[i].state == pre_self_.page_array@[i].state);
        assert(post2_self_.page_array@[i].state == pre_self_.page_array@[i].state);
        assert(post1_self_.page_array@[i].is_io_page == pre_self_.page_array@[i].is_io_page);
        assert(post2_self_.page_array@[i].is_io_page == pre_self_.page_array@[i].is_io_page);
        assert(post1_self_.page_array@[i].rev_pointer == pre_self_.page_array@[i].rev_pointer);
        assert(post2_self_.page_array@[i].rev_pointer == pre_self_.page_array@[i].rev_pointer);
        assert(post1_self_.page_array@[i].ref_count == pre_self_.page_array@[i].ref_count);
        assert(post2_self_.page_array@[i].ref_count == pre_self_.page_array@[i].ref_count);
        assert(post1_self_.page_array@[i].owning_container == pre_self_.page_array@[i].owning_container);
        assert(post2_self_.page_array@[i].owning_container == pre_self_.page_array@[i].owning_container);
        assert(post1_self_.page_array@[i].mappings =~= mapping);
        assert(post2_self_.page_array@[i].mappings =~= mapping);
        assert(post1_self_.page_array@[i].io_mappings =~= pre_self_.page_array@[i].io_mappings);
        assert(post2_self_.page_array@[i].io_mappings =~= pre_self_.page_array@[i].io_mappings);
    } else {
        // For i != index, both per-index `forall|i|` ensures fire on this i:
        // the body mentions both `post1_self_.page_array@[i]` and
        // `post2_self_.page_array@[i]` (and `pre_self_.page_array@[i]`),
        // matching the trigger groups of each ensures forall.
        assert(post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
        assert(post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);
    }
}

// Lift the pointwise Page equality to extensional Seq equality of the
// page_array views. The wf() ensures pin both views' lengths to NUM_PAGES.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
